class ShopifyClient {
 constructor() {
 this.apiUrl = CONFIG.apiUrl;
 this.headers = {
 'Content-Type': 'application/json',
 'X-Shopify-Storefront-Access-Token': CONFIG.storefrontToken
 };
 }
 async query(query, variables = {}) {
 const res = await fetch(this.apiUrl, {
 method: 'POST',
 headers: this.headers,
 body: JSON.stringify({ query, variables })
 });
 const data = await res.json();
 if (data.errors) throw new Error(data.errors[0].message);
 return data.data;
 }
 async getProducts(first = 50) {
 const q = `{
 products(first: ${first}, sortKey: CREATED_AT, reverse: true) {
 edges {
 node {
 id
 title
 handle
 description
 descriptionHtml
 productType
 tags
 availableForSale
 createdAt
 priceRange { minVariantPrice { amount currencyCode } }
 images(first: 1) { edges { node { url altText width height } } }
 variants(first: 1) { edges { node { id title availableForSale price { amount currencyCode } } } }
 }
 }
 }
 }`;
 const data = await this.query(q);
 return data.products.edges.map(e => e.node);
 }
 async getProductByHandle(handle) {
 const q = `{
 productByHandle(handle: "${handle}") {
 id
 title
 handle
 description
 descriptionHtml
 productType
 tags
 availableForSale
 createdAt
 priceRange { minVariantPrice { amount currencyCode } }
 images(first: 5) { edges { node { url altText width height } } }
 variants(first: 10) {
 edges {
 node {
 id
 title
 price { amount currencyCode }
 availableForSale
 }
 }
 }
 }
 }`;
 const data = await this.query(q);
 return data.productByHandle;
 }
 async getCollections(first = 50) {
 const q = `{
 collections(first: ${first}) {
 edges {
 node {
 id
 title
 handle
 description
 image { url }
 products(first: 8) {
 edges { node { id title handle priceRange { minVariantPrice { amount } } images(first:1) { edges { node { url } } } } }
 }
 }
 }
 }
 }`;
 const data = await this.query(q);
 return data.collections.edges.map(e => e.node);
 }
 formatPrice(amount, currency = 'EUR') {
 return new Intl.NumberFormat('fr-FR', { style: 'currency', currency }).format(parseFloat(amount));
 }
 isNew(createdAt, days = 14) {
 const d = new Date(createdAt);
 const now = new Date();
 return (now - d) / (1000 * 60 * 60 * 24) < days;
 }
}
const shopify = new ShopifyClient();